import React, { Component } from "react";

class Tools extends Component {
  toolsList = [
    {
      id: 1,
      tools: [
        "JavaScript",
        "Angular",
        "ReactJS",
        "SASS",
        "HTML5",
        "PHP",
        "MySQL",
        "ExpressJS",
        "npm",
        "Git",
        "Bitbucket",
        "Jira",
        "Confluence",
        "NodeJS",
        "APIs",
        "Docker",
        "MongoDB",
        "Adobe CC",
        "FIgma",
      ],
    },
  ];
  render() {
    const toolsStyle = {
      display: "flex",
      flexWrap: "wrap",
      justifyContent: "center",
    };
    return (
      <div className="row">
        {this.toolsList.map(({ tools }, i) => (
          <ul key={i} style={toolsStyle}>
            {tools.map((x, j) => (
              <li key={j}>{x}</li>
            ))}
          </ul>
        ))}
      </div>
    );
  }
}

export default Tools;
